using Microsoft.EntityFrameworkCore;
class BlogContext : DbContext
{
    public DbSet<Blog> Blogs => Set<Blog>();
    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        modelBuilder.Entity<Blog>(b =>
        {
            // Breaking change 1: Discriminator property renamed from "Discriminator" to "$type".
            // Keep old name so existing documents and raw SQL queries still work.
            b.HasDiscriminator<string>("Discriminator");

            // Breaking change 2: Cosmos `id` no longer includes the discriminator prefix.
            // EF 8 stored id as "Blog|1"; EF 9 stores just "1".
            // Convert to preserve the old format for existing documents.
            b.Property(e => e.Id)
             .HasConversion(
                 id => $"Blog|{id}",
                 id => id.StartsWith("Blog|") ? id.Substring(5) : id);

            // Breaking change 3: HasIndex now throws on the Cosmos provider
            // (was silently ignored in EF 8). Removed.
        });
    }
}
class Blog { public string Id { get; set; } public string Name { get; set; } }

